    vid.v v1                                      # v1 = [0,1,2,...]
    vmv.v.i v0, 0                                 # Reset mask value to 0
    vmsltu.vx v0, v1, x6                          # v0[i] = (i < VLMAX) ? 1 : 0
    li x5, 1                                      # Load desired vl value
    vsetvli x0, x5, e16, m1, tu, mu
    la x15, vd_random_base_065                    # Load address of desired value
    vle16.v v27, (x15)                            # Load desired value from memory into v27
    la x23, vector_ls_random_base                 # Load address pointer integer register for loads
    csrr x1, vtype                                # save vtype register for after load
    csrr x9, vl                                   # save vl register for after load
    vsetvli x0, x9, e8, m1, tu, mu                # set lmul to 1 for load
    la x3, vs2_random_base_065                    # Load address of desired value
    vle8.v v0, (x3)                               # Load desired value from memory into v0
    vsetvl x0, x9, x1                             # restore vl and vtype setting
    csrr x30, vtype                               # save vtype register for after load
    csrr x14, vl                                  # save vl register for after load
    vsetvl x8, x0, x30                            # set vl to vlmax
    add x8, x8, x8                                # save vlmax * 2
    vsetvli x0, x14, e8, m1, ta, ma               # setting sew to vs2 eew
    li x17, 127                                   #  make sure the number is positive since it will be 0 extended to XLEN
    vand.vx v0, v0, x17                           #  
    vrem.vx v0, v0, x8                            # ensure all values are within (-2*vlmax, 2*vlmax)
    vand.vi v0, v0, -2                            # sew-aligning elements
    vsetvl x0, x14, x30                           # restore vl and vtype setting
    vsetivli x0, 1, e64, m1, tu, mu
    vmv.v.i v0, 1
    vsetivli x0, 1, e16, m1, tu, mu
    Vls16_vloxei8_v_cg_cp_custom_masked_vs2_v0:
    vloxei8.v v27, (x23), v0, v0.t
    vsetivli x0, 1, e16, m1, tu, mu               # set SEW=16, LMUL=1, VL=1 before signature check
    # RVTEST_SIGUPD_V(_CMP, _SIG_PTR, _LINK_REG, _TEMP_REG, _VTMP, _MTMP, _SEW, _OFFSET, _VREG, _INST_PTR, _STR_PTR)
    RVTEST_SIGUPD_V(vmsne.vv, x24, x5, x4, v6, v9, 16, 8, v27, Vls16_vloxei8_v_cg_cp_custom_masked_vs2_v0, test_127_str)# Check if v27 contains the expected result. x24 is the signature ptr, x5 is the link ptr, x4 is a temp reg.
#endif

